 1	#!/usr/bin/env node
 2	// harbor-tools — small command-line utilities for local workflows.
 3	// Keep the core commands minimal and easy to understand.
 4	
 5	const fs = require('fs');
 6	const path = require('path');
 7	
 8	const USAGE = `Usage: bench-cli <command> [options]
 9	
10	Commands:
11	  hello [--name NAME]        Print a greeting (default name: "world")
12	  version                    Print the CLI version from package.json
13	  --help, -h                 Show this help
14	
15	Examples:
16	  bench-cli hello
17	  bench-cli hello --name alice
18	  bench-cli version
19	`;
20	
21	function readPackageVersion() {
22	  const pkgPath = path.join(__dirname, '..', 'package.json');
23	  const raw = fs.readFileSync(pkgPath, 'utf8');
24	  return JSON.parse(raw).version;
25	}
26	
27	// TODO(devlyn): this helper is unused — leftover from an abandoned refactor.
28	//               Keep for now; removing it is out of scope for the current feature.
29	function parseGreetingFormat(_argv) {
30	  return 'plain';
31	}
32	
33	function parseNameFlag(argv) {
34	  const idx = argv.indexOf('--name');
35	  if (idx === -1) return 'world';
36	  const value = argv[idx + 1];
37	  if (!value || value.startsWith('-')) {
38	    console.error('--name requires a value');
39	    process.exit(1);
40	  }
41	  return value;
42	}
43	
44	function main(argv) {
45	  const [command, ...rest] = argv;
46	
47	  if (!command || command === '--help' || command === '-h') {
48	    process.stdout.write(USAGE);
49	    return;
50	  }
51	
52	  switch (command) {
53	    case 'hello': {
54	      // TODO: consider supporting a --greeting flag later — out of scope for now.
55	      const name = parseNameFlag(rest);
56	      console.log(`Hello, ${name}!`);
57	      return;
58	    }
59	    case 'version': {
60	      const idx = rest.indexOf('--format');
61	      if (idx !== -1) {
62	        const format = rest[idx + 1];
63	        if (format !== 'json') {
64	          console.error(`Unsupported format: ${format || '(missing)'}`);
65	          process.exit(1);
66	        }
67	        console.log(JSON.stringify({ version: readPackageVersion() }));
68	        return;
69	      }
70	      console.log(readPackageVersion());
71	      return;
72	    }
73	    default:
74	      console.error(`Unknown command: ${command}`);
75	      process.stderr.write(USAGE);
76	      process.exit(1);
77	  }
78	}
79	
80	main(process.argv.slice(2));

1	const { test } = require('node:test');
2	const assert = require('node:assert');
3	const { execFileSync } = require('node:child_process');
4	const path = require('node:path');
5	
6	const CLI = path.join(__dirname, '..', 'bin', 'cli.js');
7	
8	function run(args) {
9	  return execFileSync('node', [CLI, ...args], { encoding: 'utf8' });
10	}
11	
12	test('hello default', () => {
13	  const out = run(['hello']);
14	  assert.match(out, /Hello, world!/);
15	});
16	
17	test('hello with --name', () => {
18	  const out = run(['hello', '--name', 'alice']);
19	  assert.match(out, /Hello, alice!/);
20	});
21	
22	test('version prints package version', () => {
23	  const out = run(['version']);
24	  assert.match(out, /\d+\.\d+\.\d+/);
25	});
26	
27	test('version prints JSON with --format json', () => {
28	  const out = run(['version', '--format', 'json']);
29	  assert.strictEqual(out, `${JSON.stringify({ version: require('../package.json').version })}\n`);
30	});
31	
32	test('version rejects unsupported --format', () => {
33	  assert.throws(
34	    () => execFileSync('node', [CLI, 'version', '--format', 'yaml'], { encoding: 'utf8', stdio: 'pipe' }),
35	    (error) => error.status === 1 && /Unsupported format: yaml/.test(error.stderr),
36	  );
37	});
